INSERT INTO contents (slug, title, excerpt, full_content, type, category, action_code, author, published_date, tags) VALUES

(
  'coltivazione-idroponica-canapa-puglia',
  'Sistemi Idroponici per la Coltivazione di Canapa in Puglia',
  'Il CNR-ISPA di Bari ha sviluppato e testato sistemi di coltivazione idroponica per varietà di canapa industriale adatte al clima pugliese, ottenendo rese superiori del 40% rispetto alla coltivazione tradizionale.',
  E'## Introduzione\n\nLa coltivazione idroponica della canapa rappresenta una delle frontiere più promettenti per la filiera canapicola pugliese. Il progetto HEMPRO ha avviato una serie di sperimentazioni presso le serre del CNR-ISPA di Bari per valutare l''efficacia di diversi sistemi idroponici.\n\n## Metodologia\n\nSono stati testati tre sistemi principali:\n\n- **NFT (Nutrient Film Technique)**: sottile film di soluzione nutritiva in circolazione continua\n- **DWC (Deep Water Culture)**: radici sospese in soluzione ossigenata\n- **Sistema a substrato inerte**: perlite e fibra di cocco come supporto radicale\n\n## Risultati Preliminari\n\nI dati raccolti nelle prime due stagioni di sperimentazione mostrano:\n\n| Sistema | Resa (g/m²) | Contenuto CBD | Consumi idrici |\n|---------|-------------|---------------|----------------|\n| NFT | 850 | 4.2% | -55% |\n| DWC | 920 | 4.8% | -60% |\n| Substrato | 780 | 3.9% | -45% |\n\nRispetto alla coltivazione in campo aperto, tutti i sistemi mostrano una riduzione significativa dei consumi idrici e un incremento della concentrazione di principi attivi.\n\n## Conclusioni\n\nI risultati preliminari confermano la fattibilità tecnica ed economica della coltivazione idroponica della canapa in ambiente mediterraneo. La prossima fase prevede l''ottimizzazione delle soluzioni nutritive specifiche per massimizzare il profilo nutraceutico.',
  'SCIENTIFIC',
  'Coltivazione',
  'AZIONE 1A',
  'CNR-ISPA Bari',
  '2026-01-15',
  ARRAY['idroponica', 'coltivazione', 'canapa', 'Puglia', 'sostenibilità']
),

(
  'analisi-nutraceutica-profilo-aminoacidico',
  'Profilo Amminoacidico della Canapa Industriale: Analisi HPLC',
  'Studio completo del profilo amminoacidico di sei varietà di canapa industriale coltivate in Puglia, con protocolli HPLC sviluppati dal laboratorio di biochimica del CNR-ISPA.',
  E'## Obiettivo della Ricerca\n\nLa caratterizzazione del profilo amminoacidico della canapa industriale è fondamentale per validarne il potenziale come proteina alternativa nel mercato Novel Food. Il CNR-ISPA ha sviluppato protocolli analitici specifici basati su cromatografia liquida ad alta prestazione (HPLC).\n\n## Varietà Analizzate\n\nSono state analizzate sei varietà certificate:\n\n1. **Futura 75** (Francia)\n2. **Finola** (Finlandia)\n3. **Carmagnola** (Italia)\n4. **Felina 32** (Francia)\n5. **Uso 31** (Ungheria)\n6. **Santhica 27** (Francia)\n\n## Protocollo Analitico\n\nIl metodo prevede:\n\n- Estrazione proteica alcalina (pH 9.5)\n- Idrolisi acida con HCl 6N a 110°C per 24h\n- Derivatizzazione pre-colonna con OPA/FMOC\n- Separazione su colonna C18 con gradiente binario\n- Rilevazione fluorimetrica (Ex 340nm / Em 450nm)\n\n## Risultati\n\nTutte le varietà analizzate mostrano un profilo amminoacidico completo, con presenza di tutti gli amminoacidi essenziali. La varietà **Finola** presenta il contenuto proteico più elevato (28.5% s.s.) con un indice PDCAAS di 0.87.\n\n## Implicazioni per il Novel Food\n\nI dati ottenuti supportano la classificazione della farina di canapa come proteina di alta qualità, comparabile alla soia ma con un impatto ambientale significativamente inferiore.',
  'SCIENTIFIC',
  'Nutraceutica',
  'AZIONE 2A',
  'CNR-ISPA Bari',
  '2026-01-28',
  ARRAY['HPLC', 'amminoacidi', 'proteine', 'analisi', 'nutraceutica']
),

(
  'sviluppo-tempeh-canapa-meat-substitute',
  'Tempeh di Canapa: Sviluppo di un Meat-Substitute Funzionale',
  'HEMPRO presenta i risultati del processo di fermentazione controllata per la produzione di tempeh a base di semi di canapa decorticati, con profilo nutrizionale ottimizzato per il mercato plant-based.',
  E'## Il Progetto Tempeh\n\nNell''ambito del workpackage dedicato all''innovazione alimentare, il team di Food Hub SRL SB in collaborazione con CNR-ISPA ha sviluppato un processo produttivo per la realizzazione di tempeh di canapa, prodotto fermentato ad alto contenuto proteico destinato al mercato dei sostituti della carne.\n\n## Processo Produttivo\n\n### Fase 1 - Preparazione del substrato\nI semi di canapa decorticati vengono sottoposti a:\n- Ammollo in acqua acidulata (pH 4.5) per 12 ore\n- Cottura a vapore a 100°C per 45 minuti\n- Raffreddamento e inoculo con spore di *Rhizopus oligosporus*\n\n### Fase 2 - Fermentazione\nIncubazione a 30°C per 36-48 ore in celle termostatate con:\n- Umidità relativa: 85-90%\n- Aerazione controllata\n- Monitoraggio continuo del pH e della temperatura\n\n### Fase 3 - Stabilizzazione\nIl prodotto finito viene:\n- Pastorizzato a 75°C per 30 minuti\n- Confezionato in atmosfera modificata (N₂/CO₂)\n- Stoccato a 4°C\n\n## Profilo Nutrizionale\n\n| Parametro | Tempeh Canapa | Tempeh Soia |\n|-----------|---------------|-------------|\n| Proteine | 24.2 g/100g | 18.5 g/100g |\n| Grassi | 11.8 g/100g | 9.2 g/100g |\n| Omega-3 | 3.1 g/100g | 0.4 g/100g |\n| Fibra | 8.4 g/100g | 4.3 g/100g |\n| Vitamina B12 | 0.8 µg/100g | 0.1 µg/100g |\n\n## Prossimi Passi\n\nIl prodotto è attualmente in fase di validazione sensoriale con panel test. La commercializzazione è prevista per il secondo semestre 2026 tramite i canali di distribuzione di Ortogourmet.',
  'SCIENTIFIC',
  'Food Innovation',
  'AZIONE 3B',
  'Food Hub SRL SB',
  '2026-02-10',
  ARRAY['tempeh', 'fermentazione', 'plant-based', 'meat-substitute', 'proteine']
),

(
  'microgreens-canapa-produzione-caratteristiche',
  'Microgreens di Canapa: Valore Nutrizionale e Tecniche di Produzione',
  'I microgreens di canapa rappresentano una delle innovazioni più interessanti del progetto HEMPRO: germogli ricchi di antiossidanti, clorofilla e acidi grassi essenziali, con ciclo produttivo di soli 7-10 giorni.',
  E'## Cosa sono i Microgreens\n\nI microgreens sono germogli di piante raccolti allo stadio delle prime foglie vere (7-14 giorni dalla germinazione). Nel caso della canapa (*Cannabis sativa* L.), questa fase corrisponde a un prodotto ad altissima densità nutrizionale.\n\n## Tecnica di Produzione HEMPRO\n\nIl protocollo sviluppato dal CNR-ISPA prevede:\n\n**Substrato**: tappetini in fibra di cocco biodegradabile\n\n**Semina**: densità di 40g/dm² di semi decorticati pre-germinati\n\n**Condizioni ambientali**:\n- Temperatura: 20-22°C\n- Fotoperiodo: 16h luce / 8h buio\n- Illuminazione: LED full spectrum 200 µmol/m²/s\n- Umidità: 65-70%\n\n**Raccolta**: al momento della comparsa dei cotiledoni completamente aperti\n\n## Composizione Nutrizionale\n\nI microgreens di canapa mostrano concentrazioni di nutrienti da 4 a 40 volte superiori alle foglie mature:\n\n- **Vitamina C**: 42 mg/100g\n- **Vitamina E (α-tocoferolo)**: 18 mg/100g\n- **β-carotene**: 12 mg/100g\n- **Clorofilla totale**: 380 mg/100g\n- **Acido α-linolenico (ALA)**: 2.8 g/100g\n\n## Applicazioni Food\n\nI microgreens sono stati testati in collaborazione con Ortogourmet in applicazioni di:\n- Insalate gourmet\n- Guarnizioni per piatti di pesce\n- Smoothie e succhi funzionali\n- Composizioni per il mercato HoReCa',
  'SCIENTIFIC',
  'Coltivazione',
  'AZIONE 1B',
  'CNR-ISPA Bari',
